module adder_4bit(input alt_A, B, Cin, output Sum, Cout);
    assign {Cout, Sum} = alt_A + B + Cin;
endmodule

module adder_4bit(alt_A, B, Cin, Sum, Cout);
    input [3:0] alt_A, B;
    input Cin;
    output [3:0] Sum;
    output Cout;

    wire C1, C2, C3;

    full_adder FA0 (.alt_A(alt_A[0]), .B(B[0]), .Cin(Cin), .Sum(Sum[0]), .Cout(C1));
    full_adder FA1 (.alt_A(alt_A[1]), .B(B[1]), .Cin(C1), .Sum(Sum[1]), .Cout(C2));
    full_adder FA2 (.alt_A(alt_A[2]), .B(B[2]), .Cin(C2), .Sum(Sum[2]), .Cout(C3));
    full_adder FA3 (.alt_A(alt_A[3]), .B(B[3]), .Cin(C3), .Sum(Sum[3]), .Cout(Cout));
endmodule
